onOptionChange:
{{
storeValue("deptReadyArchive", false)
.then(() => storeValue("selectedDepartmentArchive", Select_ArchiveDepartment.selectedOptionValue))
.then(() => GetQuestionsByDeptArchive.run())
.then(() => GetAnswersArchive.run())
.then(() => {
  const existing = {};
  (GetAnswersArchive.data || []).forEach(a => {
    existing[String(a.QuestionId)] = {
      YesNo: a.YesNo,
      Answer: a.Answer,
      AnsweredBy: a.AnsweredBy,
      AnsweredDate: a.AnsweredDate,
      ResponsiblePerson: a.ResponsiblePerson,
      Action: a.Action,
      DueDate: a.DueDate
    };
  });
  return storeValue("answers_Archive", existing)
    .then(() => storeValue("originalAnswers_Archive", JSON.parse(JSON.stringify(existing))));
})
.then(() => storeValue("deptReadyArchive", true))
.catch((err) => {
  console.error("Select_ArchiveDepartment failed:", err);
  showAlert("Failed to load department data", "error");
  storeValue("deptReadyArchive", false);
})
}}
